// Function to compute HMAC-SHA256 using the modern EVP layer
int compute_hmac_sha256(const unsigned char *key, int key_len,
                        const unsigned char *msg, int msg_len,
                        unsigned char *hmac_result)
{
    EVP_MAC_CTX *mac_ctx = NULL;
    int result = 0;

    // 1. Setup the MAC context (using EVP_MAC layer)
    // Note: For simple HMAC, you often use HMAC_Init_ex/Update/Final, but the recommendation points towards EVP_MAC.
    // For pure HMAC, we initialize the context for the digest.
    mac_ctx = EVP_MAC_CTX_new();
    if (!mac_ctx) {
        fprintf(stderr, "Failed to create EVP_MAC_CTX\n");
        return -1;
    }

    // 2. Set the algorithm (SHA256 for HMAC)
    // HMAC uses the underlying digest (SHA256) within the MAC framework.
    // Note: EVP_MAC functions often deal with generic MACs. For HMAC, we often use the dedicated HMAC functions,
    // but adhering to the documented preference for the MAC layer setup:
    if (EVP_MAC_init(mac_ctx, EVP_sha256(), NULL) != 1) {
        fprintf(stderr, "Failed to initialize HMAC context with SHA256\n");
        EVP_MAC_CTX_free(mac_ctx);
        return -1;
    }

    // 3. Set the key
    if (EVP_MAC_set_mem(mac_ctx, key, key_len) != 1) {
        fprintf(stderr, "Failed to set key\n");
        EVP_MAC_CTX_free(mac_ctx);
        return -1;
    }

    // 4. Update with the message
    if (EVP_MAC_update(mac_ctx, msg, msg_len) != 1) {
        fprintf(stderr, "Failed to update MAC context with message\n");
        EVP_MAC_CTX_free(mac_ctx);
        return -1;
    }

    // 5. Finalize the computation
    // The result is placed in the output buffer (hmac_result)
    if (EVP_MAC_final(mac_ctx, hmac_result, NULL) != 1) {
        fprintf(stderr, "Failed to finalize MAC computation\n");
        EVP_MAC_CTX_free(mac_ctx);
        return -1;
    }

    result = 1;
    EVP_MAC_CTX_free(mac_ctx);
    return result;
}

